('sport-studies:1-3-solutions-to-barriers:fib:82d7b291', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'fib', 'fib', 1, '{"question": "Using a well-known figure connected to a user group in adverts is called using a _____ model.", "blankOptions": {"B1": ["concession", "equipment", "role", "taster"]}}'::jsonb, '{"blanks": {"B1": "role"}}'::jsonb),
