('sport-studies:1-3-solutions-to-barriers:fib:a4bc58c2', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'fib', 'fib', 1, '{"question": "Fitting a pool hoist or a hearing loop is an example of appropriate facilities and _____.", "blankOptions": {"B1": ["times", "access", "equipment", "taster"]}}'::jsonb, '{"blanks": {"B1": "equipment"}}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:fib:1f3d1fd7', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'fib', 'fib', 1, '{"question": "Widening doorways and adding ramps around a venue is an example of improved _____.", "blankOptions": {"B1": ["access", "role", "concession", "times"]}}'::jsonb, '{"blanks": {"B1": "access"}}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:fib:c77e03e7', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'fib', 'fib', 1, '{"question": "A reduced price aimed at a group such as students or over-60s is called a _____.", "blankOptions": {"B1": ["role", "concession", "access", "equipment"]}}'::jsonb, '{"blanks": {"B1": "concession"}}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:match:23230f29', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Provision”?", "options": ["Offering appropriate programmes, sessions, activities and times for a specific user group", "Ramps, wide doorways and clear paths that make a whole venue usable for all groups", "Advertising aimed directly at a particular user group rather than a general audience", "A person from or connected to a group whose example encourages that group to take part"]}'::jsonb, '{"answer": 0, "explain": "“Provision” means: Offering appropriate programmes, sessions, activities and times for a specific user group"}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:match:417c6b97', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Targeted promotion”?", "options": ["Advertising aimed directly at a particular user group rather than a general audience", "Physical features such as pool hoists, hearing loops or tactile signage that remove a barrier", "Ramps, wide doorways and clear paths that make a whole venue usable for all groups", "A person from or connected to a group whose example encourages that group to take part"]}'::jsonb, '{"answer": 0, "explain": "“Targeted promotion” means: Advertising aimed directly at a particular user group rather than a general audience"}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:match:443f6188', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Role model”?", "options": ["A person from or connected to a group whose example encourages that group to take part", "Extra buses, pick-up services or better links that help a group reach a venue", "A reduced price aimed at a group such as students, over-60s or unemployed people", "Advertising aimed directly at a particular user group rather than a general audience"]}'::jsonb, '{"answer": 0, "explain": "“Role model” means: A person from or connected to a group whose example encourages that group to take part"}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:match:d9fd8731', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Taster session”?", "options": ["A free trial of an activity that lets a group try it before committing any money", "Offering appropriate programmes, sessions, activities and times for a specific user group", "Physical features such as pool hoists, hearing loops or tactile signage that remove a barrier", "Extra buses, pick-up services or better links that help a group reach a venue"]}'::jsonb, '{"answer": 0, "explain": "“Taster session” means: A free trial of an activity that lets a group try it before committing any money"}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:match:48313949', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Transport solution”?", "options": ["Extra buses, pick-up services or better links that help a group reach a venue", "Offering appropriate programmes, sessions, activities and times for a specific user group", "Advertising aimed directly at a particular user group rather than a general audience", "A reduced price aimed at a group such as students, over-60s or unemployed people"]}'::jsonb, '{"answer": 0, "explain": "“Transport solution” means: Extra buses, pick-up services or better links that help a group reach a venue"}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:match:15766289', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Accessible facilities and equipment”?", "options": ["Physical features such as pool hoists, hearing loops or tactile signage that remove a barrier", "Offering appropriate programmes, sessions, activities and times for a specific user group", "A free trial of an activity that lets a group try it before committing any money", "A person from or connected to a group whose example encourages that group to take part"]}'::jsonb, '{"answer": 0, "explain": "“Accessible facilities and equipment” means: Physical features such as pool hoists, hearing loops or tactile signage that remove a barrier"}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:match:67e8b129', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Improved access”?", "options": ["Physical features such as pool hoists, hearing loops or tactile signage that remove a barrier", "Ramps, wide doorways and clear paths that make a whole venue usable for all groups", "Advertising aimed directly at a particular user group rather than a general audience", "Offering appropriate programmes, sessions, activities and times for a specific user group"]}'::jsonb, '{"answer": 1, "explain": "“Improved access” means: Ramps, wide doorways and clear paths that make a whole venue usable for all groups"}'::jsonb),
('sport-studies:1-3-solutions-to-barriers:match:a701d7af', 'sport-studies', 'sport-studies:1-3-solutions-to-barriers', '1.3 Solutions to Barriers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Concessionary pricing”?", "options": ["Offering appropriate programmes, sessions, activities and times for a specific user group", "A reduced price aimed at a group such as students, over-60s or unemployed people", "A free trial of an activity that lets a group try it before committing any money", "Advertising aimed directly at a particular user group rather than a general audience"]}'::jsonb, '{"answer": 1, "explain": "“Concessionary pricing” means: A reduced price aimed at a group such as students, over-60s or unemployed people"}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:exam:3a2e71dd', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'exam', 'mcq', 1, '{"num": "2", "question": "Which factor is most likely to explain why a sport gets a short-term surge in interest immediately after a national team wins a major trophy?", "options": ["The provision of facilities available in the local area", "The high-level success of individuals and teams", "The amount and range of media coverage a sport typically receives during an average season", "Environmental and climate influences on which sports can be played across the UK"], "hint": "Think about what has just happened in the question — a win at the highest level.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — The high-level success of individuals and teams.</strong></p>\n<ul>\n<li>A major win at the highest level typically causes a short-term \"feel-good bounce\" in interest, participation and coverage.</li>\n<li>The other options describe ongoing factors, not the immediate cause of a surge right after a single tournament win.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:mcq:f0238146', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'mcq', 'mcq', 1, '{"question": "Which best explains how a rise in the number of people playing a sport tends to affect its popularity?", "options": ["More participants usually raise overall popularity, since players often go on to watch, follow and talk about the sport too", "It has no real connection to popularity whatsoever, because participation numbers and general popularity are always two entirely separate and unrelated things", "It always causes the sport to be added permanently to the school national curriculum the following year", "It automatically doubles the amount of prize money available at every professional competition"]}'::jsonb, '{"answer": 0, "explain": "Rising participation tends to raise popularity because players often become fans, spectators and word-of-mouth promoters too. The other options invent effects the factor doesn''t actually have."}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:mcq:e5ac8521', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'mcq', 'mcq', 1, '{"question": "A town removes its only public swimming pool. What effect is this most likely to have on swimming''s local popularity?", "options": ["None, because facility provision never has any influence on whether people can take part in a sport", "Swimming becomes instantly more popular, because people enjoy a challenge when facilities disappear", "It is likely to lower popularity, because people can no longer easily access somewhere to swim", "It has no effect locally, but it makes swimming much more popular in every neighbouring town instead"]}'::jsonb, '{"answer": 2, "explain": "Losing the only local facility removes easy access, which tends to lower participation and popularity — it does not raise it, and it doesn''t magically boost swimming elsewhere."}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:mcq:16c3423f', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'mcq', 'mcq', 1, '{"question": "Why does the UK produce relatively few elite alpine skiers compared with mountainous countries?", "options": ["British people have never once shown any interest in snow sports of any kind", "The UK''s climate and terrain rarely provide the reliable snow and mountains that skiing needs", "Skiing has been officially banned by every national governing body across the whole of the UK", "No UK television channel has ever broadcast any footage of a ski competition at all"]}'::jsonb, '{"answer": 1, "explain": "Environmental and climate influences are the real reason — the UK''s terrain and weather rarely give the reliable snow and mountains skiing needs, unlike a lack of interest, a ban, or zero coverage."}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:mcq:fc057690', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'mcq', 'mcq', 1, '{"question": "A new stadium opens with cheap tickets and a great matchday atmosphere for a local team. What effect is this likely to have on that sport''s popularity?", "options": ["It falls, because larger crowds at a cheaper new stadium always make the atmosphere feel worse for loyal regular fans", "It stays exactly the same, because where people go to watch sport never really changes their genuine interest in it", "It only affects popularity among the small number of people who already owned season tickets at the old ground", "It rises, because affordable live opportunities can turn spectators into new fans and participants"]}'::jsonb, '{"answer": 3, "explain": "Cheap, accessible live spectator opportunities tend to raise popularity by turning casual watchers into fans and even participants — not lower it or leave it unchanged."}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:mcq:a9ed573b', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'mcq', 'mcq', 1, '{"question": "A sport that used to get almost no TV coverage suddenly gets a full season broadcast live every week. What effect does this tend to have?", "options": ["Popularity tends to rise, because regular coverage reaches new audiences and attracts sponsorship", "Popularity always falls, because loyal fans much prefer to attend a fixture in person rather than ever watch it on TV at home", "There is no effect at all, because television coverage has never once influenced any sport''s popularity in any way", "The sport is instantly removed from all live fixture listings published in national newspapers"]}'::jsonb, '{"answer": 0, "explain": "Regular media coverage tends to raise popularity by reaching new audiences and attracting sponsors — coverage does not automatically reduce attendance or get a sport dropped from listings."}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:mcq:df38d387', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'mcq', 'mcq', 1, '{"question": "A UK team wins a major international tournament for the first time in decades. What short-term effect does this typically have on the sport?", "options": ["None, because results at major tournaments never change public interest in a sport", "The opposite of what you''d expect — interest and participation usually fall straight away", "A surge in interest, participation and coverage, sometimes called a feel-good bounce", "It only affects the players on that specific team and nobody else who follows the sport"]}'::jsonb, '{"answer": 2, "explain": "High-level success typically produces a short-term ''feel-good bounce'' — a surge in interest, participation and coverage — rather than no change, a fall, or an effect limited only to the players."}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:tf:ba596faa', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'tf', 'tf', 1, '{"question": "Every one of the eight popularity factors can only ever raise a sport''s popularity, never lower it."}'::jsonb, '{"answer": false, "explain": "Each factor can push popularity in EITHER direction — for example, poor facility provision lowers popularity just as good provision raises it."}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:tf:fdff4dc1', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'tf', 'tf', 1, '{"question": "A short-term surge in interest after a major tournament win is sometimes called a feel-good bounce."}'::jsonb, '{"answer": true, "explain": "That''s the term used for the temporary rise in participation, interest and coverage that often follows high-level success."}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:tf:6ccb0ec0', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'tf', 'tf', 1, '{"question": "The UK''s climate and terrain can limit how popular certain snow- or ice-based sports become nationally."}'::jsonb, '{"answer": true, "explain": "Environmental and climate influences are a genuine factor — the UK rarely provides the conditions some sports need all year round."}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:tf:2bd4a7af', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'tf', 'tf', 1, '{"question": "Social acceptability has no connection to concerns about violence or fairness in a sport."}'::jsonb, '{"answer": false, "explain": "Social acceptability IS partly about this — concerns about violence, cruelty or unfairness can make a sport less socially acceptable and lower its popularity."}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:tf:0c6b2f89', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'tf', 'tf', 1, '{"question": "A wider range of positive role models tends to help more people see a sport as ''for them''."}'::jsonb, '{"answer": true, "explain": "Role models people can relate to (across gender, ethnicity, disability and background) encourage more people to get involved."}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:tf:3f5895cb', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'tf', 'tf', 1, '{"question": "Removing an accessible local facility for a sport usually has no effect on how popular it stays."}'::jsonb, '{"answer": false, "explain": "Losing easy access to facilities tends to lower participation, since people can no longer take part as easily — that in turn can lower popularity."}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:learn:331b63ed', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'learn', 'mcq', 1, '{"readingTitle": "What makes a sport popular — participation, facilities and climate", "reading": "<h4>Popularity moves up and down</h4>\n<ul>\n<li>A sport''s popularity in the UK is not fixed. Several factors push it <strong>up</strong> or <strong>down</strong> over time, and the same factor can work in either direction depending on what happens.</li>\n<li>The exam skill: don''t just name a factor — say which <strong>direction</strong> it pushed popularity in your example, and explain the <strong>effect</strong> this had.</li>\n</ul>\n<h4>Factor 1 — the number of people participating</h4>\n<ul>\n<li>When more people take part in a sport, its overall popularity tends to rise — participants often go on to watch it, follow it and talk about it too.</li>\n<li>If participation falls (perhaps because a sport is seen as old-fashioned or hard to access), popularity can shrink alongside it.</li>\n</ul>\n<h4>Factor 2 — the provision of facilities</h4>\n<ul>\n<li>A sport needs somewhere to be played. Plenty of accessible, well-maintained venues and equipment make it easy to take up, which raises popularity.</li>\n<li>Where facilities are scarce, expensive to hire, or a long way from where people live, they cannot get involved even if they want to, so popularity stays low.</li>\n</ul>\n<h4>Factor 3 — environmental and climate influences</h4>\n<ul>\n<li>The UK''s weather and geography make some activities easy to access all year (such as pitch and court sports) but limit others that need conditions like reliable snow, ice, open water or warm temperatures.</li>\n<li>A sport that depends on conditions the UK rarely provides will struggle to build mass popularity here, however popular that sport is in other countries.</li>\n</ul>", "question": "A sport can only be played on natural ice that forms reliably for several months a year. Which factor best explains why this limits its popularity across most of the UK?", "options": ["Environmental and climate influences, because the UK rarely provides those conditions consistently", "Social acceptability, because wider society has generally decided the sport is not respectable enough to watch or take part in", "Having a wide pool of relatable, high-profile athletes who inspire newcomers to give the sport a go", "Live spectator opportunities, because grounds selling tickets to matches are always too expensive"]}'::jsonb, '{"answer": 0, "explain": "The UK''s climate rarely gives reliable natural ice for long periods, so environment/climate is the factor limiting this sport — not role models, acceptability or ticket prices."}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:learn:8e8718fe', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'learn', 'mcq', 1, '{"readingTitle": "Watching it happen — spectators, media coverage and elite success", "reading": "<h4>Factor 4 — live spectator opportunities</h4>\n<ul>\n<li>When people can go and watch a sport live — affordably, nearby, with a good atmosphere — it builds a following, and some spectators go on to become new participants themselves.</li>\n<li>If tickets are expensive, venues are far away, or few live fixtures are staged at all, the sport stays out of sight and popularity struggles to grow.</li>\n</ul>\n<h4>Factor 5 — the amount and range of media coverage</h4>\n<ul>\n<li>Regular TV, radio, print and online coverage keeps a sport in the public eye, attracts sponsorship money and inspires new fans and participants.</li>\n<li>A sport that receives little coverage, or coverage of only one narrow part of it, struggles to reach new audiences even if it is genuinely exciting to watch.</li>\n</ul>\n<h4>Factor 6 — the high-level success of individuals and teams</h4>\n<ul>\n<li>When UK athletes or teams succeed at the highest level (winning a major tournament or an international medal), the sport usually gets a short-term surge in interest, participation and coverage — sometimes called a <strong>feel-good bounce</strong>.</li>\n<li>A long run of poor results at major competitions can have the opposite effect, and public interest can quietly fade away.</li>\n</ul>", "question": "A UK team wins a major international trophy for the first time in years, and club enquiries rise the following week. What does this best show?", "options": ["Elite success can cause a short-term surge in a sport''s participation and popularity", "Winning a major trophy always guarantees that a sport stays popular permanently from that point onward", "Media coverage is completely unrelated to how well a national team happens to perform", "Only players on the winning team personally benefit from any rise in popularity"]}'::jsonb, '{"answer": 0, "explain": "High-level success often produces a temporary ''feel-good bounce'' in interest and participation — it is not permanent, and it is not limited to the players themselves."}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:learn:c60ab93c', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'learn', 'mcq', 1, '{"readingTitle": "Role models, social acceptability — and the exam skill: up or down?", "reading": "<h4>Factor 7 — how relatable and visible its role models are</h4>\n<ul>\n<li>Athletes who are visible, respected, and easy to relate to (across gender, ethnicity, disability and background) encourage people who see themselves reflected in that role model to get involved.</li>\n<li>A narrow range of role models — or role models linked to bad publicity — gives fewer people a reason to see a sport as \"for them\", which can hold its popularity back.</li>\n</ul>\n<h4>Factor 8 — social acceptability</h4>\n<ul>\n<li>A sport tends to grow when wider society sees it as safe, fair and appropriate to take part in or to watch.</li>\n<li>Concerns about violence, cruelty (to people or animals), or unfairness can make a sport socially unacceptable to some people, which can lower both participation and popularity.</li>\n</ul>\n<h4>The exam skill: always say UP or DOWN, and why</h4>\n<ul>\n<li>Every one of the eight factors above can work in either direction. Weak answer: <em>\"Media coverage affects popularity.\"</em> Strong answer: <em>\"Extensive TV coverage of a major tournament exposed the sport to new audiences, which raised participation as more people wanted to try it after watching.\"</em></li>\n<li>This same skill reappears later in the course — in 1.5 (why emerging sports grow or stall) and in Topic 5 (the effects of technology and media on sport) — so it is worth mastering here first.</li>\n</ul>", "question": "Which sentence uses the exam skill correctly (names a factor, a direction, AND an effect)?", "options": ["Positive role models generally make a sport feel a little more interesting to people who already enjoy watching it", "A wider range of visible role models can raise popularity, as more people relate to them and take part", "Role models are simply one of the eight factors mentioned somewhere in the specification for this particular topic", "Some sports currently have more famous role models attached to them than other sports do"]}'::jsonb, '{"answer": 1, "explain": "Only this option names the factor, states the direction (raise), and gives the effect (more people relate and take part) — the others stop at naming or describing without direction and effect."}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:misc:92c2bce2', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> If I just name a factor like ''media coverage'', that explains why a sport''s popularity changed.</p><p><strong>✅ The correct idea:</strong> Naming the factor is only the start. The mark is for saying which DIRECTION it pushed popularity and the EFFECT this had. Weak: \"Media coverage affects popularity.\" Full marks: \"Extensive TV coverage of a tournament exposed the sport to new audiences, which raised participation as more people wanted to try it.\"</p>", "question": "An ''Explain'' question asks how a factor affected a sport''s popularity. What earns the marks?", "options": ["Naming as many of the eight different popularity factors as you can possibly remember", "Naming the factor, the direction it pushed popularity, and the effect", "Writing the factor''s name in capital letters for emphasis", "Describing a sport you personally enjoy watching"]}'::jsonb, '{"answer": 1, "explain": "Explain = factor + direction + effect. Naming the factor alone, or listing several factors, does not show the understanding the mark scheme rewards."}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:misc:0d8af502', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> These eight factors only ever make a sport MORE popular — they can''t work the other way.</p><p><strong>✅ The correct idea:</strong> Every factor can push popularity up OR down. Good facility provision raises popularity; losing facilities lowers it. Strong media coverage raises popularity; almost no coverage limits it. Always check which direction your example actually shows before you write the effect.</p>", "question": "A sport loses most of its live TV coverage over several years. What is the most likely effect on its popularity?", "options": ["It rises, because every one of these factors can only ever raise a sport''s popularity", "It is likely to fall, because losing exposure to audiences can reduce interest", "There is no possible effect on popularity from any change in coverage", "The sport instantly becomes an emerging sport as a result"]}'::jsonb, '{"answer": 1, "explain": "Losing coverage removes exposure to new audiences, so popularity is likely to fall — the same factor that can raise popularity can also lower it."}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:misc:55af0e05', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Participation and popularity are two totally separate ideas with no real link between them.</p><p><strong>✅ The correct idea:</strong> They are closely linked, which is exactly why ''the number of people participating'' is one of the eight factors. More participants tend to raise overall popularity (players often become fans and promoters too); fewer participants can shrink it. They are not identical ideas, but they clearly affect each other.</p>", "question": "Why is ''the number of people participating'' listed as a factor affecting a sport''s popularity?", "options": ["Because participation and popularity have no meaningful connection to one another at all, ever", "Because participants often go on to watch, follow and promote a sport too, which can raise popularity", "Because only fully professional, highly paid athletes ever count as genuine participants in any sport", "Because participation always falls whenever popularity rises"]}'::jsonb, '{"answer": 1, "explain": "Participants frequently become spectators, fans and word-of-mouth promoters, which is why rising participation tends to raise a sport''s wider popularity."}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:misc:0a970f6d', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Social acceptability is just about whether a sport looks ''cool'' — it has nothing to do with things like violence or fairness.</p><p><strong>✅ The correct idea:</strong> Social acceptability is specifically about whether wider society views a sport as safe, fair and appropriate. Concerns about violence, cruelty to people or animals, or unfairness are the main things that can lower it — ''looking cool'' is not the concept being tested.</p>", "question": "What does ''social acceptability'' as a popularity factor actually refer to?", "options": ["Whether a sport currently looks fashionable and trendy to teenagers specifically", "Whether wider society sees a sport as safe, fair and appropriate", "Whether a sport is expensive to take part in", "Whether a sport has an official national governing body"]}'::jsonb, '{"answer": 1, "explain": "Social acceptability concerns whether society sees a sport as safe, fair and appropriate — concerns about violence, cruelty or unfairness are what can lower it."}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:tips:650ffab2', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for this topic — what each one wants", "reading": "<p>Popularity questions can be short recall or longer applied answers. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify two factors affecting popularity\" = two factor names, nothing more. 1 mark each.</li>\n<li><strong>Explain</strong> — name the factor, give the direction (up or down), and give the effect. Use \"because\" to link them.</li>\n<li><strong>Discuss</strong> — weigh up more than one factor, applied to a scenario, and reach a judgement about which matters most or how far it would work.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1]–[2] wants one or two points; [4] in Section B wants points applied to the scenario given; [8] levelled wants balance across factors and a justified judgement.</p>", "question": "A question says: ''Identify two factors that affect a sport''s popularity [2]''. What is the safest answer?", "options": ["A long paragraph about one single factor", "Two factor names", "One factor explained in great detail", "A list of all eight factors"]}'::jsonb, '{"answer": 1, "explain": "''Identify'' + [2] = two names, one mark each. Explaining one factor in depth, or listing all eight, wastes time and risks the examiner marking only the first two anyway."}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:tips:bdacf1f2', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'tips', 'mcq', 1, '{"readingTitle": "tip — The golden rule: factor, direction, effect", "reading": "<p>The single most common way to lose marks here is stopping at the factor''s name. Build every answer as <strong>factor → direction → effect</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"Media coverage.\"</li>\n<li><strong>✅ full marks:</strong> \"Wider media coverage raised the sport''s popularity, because it exposed new audiences to the sport who then wanted to try it themselves.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named sport, club or event). You must use a detail <em>from that scenario</em>, not a general example from a different sport.</p>", "question": "In a Section B scenario about a named sports club, your example should come from...", "options": ["absolutely any sport that you happen to prefer", "the scenario you are given", "a famous athlete not mentioned anywhere in the question", "your own personal experience of a completely different sport"]}'::jsonb, '{"answer": 1, "explain": "Section B is applied — the marks are for using the scenario in front of you. A general example that ignores the scenario is capped."}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:tips:8b056bac', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where this topic appears + sentence starters", "reading": "<p><strong>Where it shows up:</strong> popularity factors appear as quick recall in <strong>Section A</strong> (identify/state), as applied points in <strong>Section B</strong> scenarios about a specific sport or event, and they feed <strong>Section C</strong> 8-mark answers discussing how to grow a sport''s popularity. The same skill links forward to 1.5 (emerging sports) and Topic 5 (technology and media).</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the eight factors as a checklist so you can always recall several under pressure.</li>\n<li>For every factor, memorise one \"up\" example and one \"down\" example — direction is where the mark often sits.</li>\n<li>In a longer answer, weigh factors against each other rather than just listing them one after another.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One factor affecting popularity here is… which raised/lowered it because…\"</li>\n<li>\"This mattered because it changed…\"</li>\n<li>\"However, on its own this factor might not be enough because…\"</li>\n</ul>", "question": "Why is it useful to know an ''up'' example AND a ''down'' example for the same factor?", "options": ["It simply fills useful space in a longer written answer without really needing to add anything new or relevant to it", "Because the exam can ask about either direction, and a fixed ''always up'' answer would be wrong for a ''down'' question", "Because every one of these eight factors only ever works in a single, fixed direction anyway", "It completely replaces the need to apply the factor to any scenario given in the question"]}'::jsonb, '{"answer": 1, "explain": "Every factor can raise OR lower popularity, so knowing both directions means you''re ready whichever way a question is framed — you still need to apply it to the scenario too."}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:fib:18b38110', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'fib', 'fib', 1, '{"question": "A sport tends to become more popular when the number of people _____ in it increases.", "blankOptions": {"B1": ["participating", "facilities", "models", "coverage"]}}'::jsonb, '{"blanks": {"B1": "participating"}}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:fib:3e0a6231', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'fib', 'fib', 1, '{"question": "Plentiful, accessible sports _____ make it easier for people to take up a sport in the first place.", "blankOptions": {"B1": ["coverage", "facilities", "models", "climate"]}}'::jsonb, '{"blanks": {"B1": "facilities"}}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:fib:889813fb', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'fib', 'fib', 1, '{"question": "A sport that needs reliable snow or ice can struggle to grow across the UK because of the _____.", "blankOptions": {"B1": ["climate", "models", "facilities", "participating"]}}'::jsonb, '{"blanks": {"B1": "climate"}}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:fib:409f2fd5', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'fib', 'fib', 1, '{"question": "Extensive media _____ keeps a sport visible to the public and can attract new fans.", "blankOptions": {"B1": ["climate", "coverage", "acceptability", "participating"]}}'::jsonb, '{"blanks": {"B1": "coverage"}}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:fib:0b10a0db', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'fib', 'fib', 1, '{"question": "A wider range of positive role _____ encourages more people who relate to them to get involved.", "blankOptions": {"B1": ["climate", "models", "acceptability", "participating"]}}'::jsonb, '{"blanks": {"B1": "models"}}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:fib:c95e8367', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'fib', 'fib', 1, '{"question": "Concerns about violence or cruelty can lower a sport''s social _____ to some people.", "blankOptions": {"B1": ["acceptability", "climate", "coverage", "models"]}}'::jsonb, '{"blanks": {"B1": "acceptability"}}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:match:1e304054', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Participation numbers”?", "options": ["The amount and range of TV, radio, print and online exposure a sport receives", "Whether wider society sees a sport as safe, fair and appropriate to take part in or watch", "How accessible, available and well-maintained a sport''s venues and equipment are", "How many people actually take part; a rise tends to raise a sport''s overall popularity"]}'::jsonb, '{"answer": 3, "explain": "“Participation numbers” means: How many people actually take part; a rise tends to raise a sport''s overall popularity"}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:match:71c39637', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Provision of facilities”?", "options": ["How accessible, available and well-maintained a sport''s venues and equipment are", "The amount and range of TV, radio, print and online exposure a sport receives", "How many people actually take part; a rise tends to raise a sport''s overall popularity", "The UK''s weather and terrain, which allow some activities easily but limit others needing snow, ice or warmth"]}'::jsonb, '{"answer": 0, "explain": "“Provision of facilities” means: How accessible, available and well-maintained a sport''s venues and equipment are"}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:match:2a24c2a7', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Environmental/climate influences”?", "options": ["How accessible, available and well-maintained a sport''s venues and equipment are", "How many people actually take part; a rise tends to raise a sport''s overall popularity", "Whether wider society sees a sport as safe, fair and appropriate to take part in or watch", "The UK''s weather and terrain, which allow some activities easily but limit others needing snow, ice or warmth"]}'::jsonb, '{"answer": 3, "explain": "“Environmental/climate influences” means: The UK''s weather and terrain, which allow some activities easily but limit others needing snow, ice or warmth"}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:match:c75a1ada', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Live spectator opportunities”?", "options": ["The chance to watch a sport in person, which can turn spectators into new fans and participants", "The UK''s weather and terrain, which allow some activities easily but limit others needing snow, ice or warmth", "Visible, respected performers people can relate to, encouraging them to take part", "How accessible, available and well-maintained a sport''s venues and equipment are"]}'::jsonb, '{"answer": 0, "explain": "“Live spectator opportunities” means: The chance to watch a sport in person, which can turn spectators into new fans and participants"}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:match:e2362f4f', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Media coverage”?", "options": ["The amount and range of TV, radio, print and online exposure a sport receives", "The UK''s weather and terrain, which allow some activities easily but limit others needing snow, ice or warmth", "How many people actually take part; a rise tends to raise a sport''s overall popularity", "Whether wider society sees a sport as safe, fair and appropriate to take part in or watch"]}'::jsonb, '{"answer": 0, "explain": "“Media coverage” means: The amount and range of TV, radio, print and online exposure a sport receives"}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:match:9df89fc7', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “High-level success”?", "options": ["The amount and range of TV, radio, print and online exposure a sport receives", "The UK''s weather and terrain, which allow some activities easily but limit others needing snow, ice or warmth", "Whether wider society sees a sport as safe, fair and appropriate to take part in or watch", "Wins by individuals or teams at the highest level, which can cause a short-term surge in interest"]}'::jsonb, '{"answer": 3, "explain": "“High-level success” means: Wins by individuals or teams at the highest level, which can cause a short-term surge in interest"}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:match:de0f8882', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Positive role models”?", "options": ["Visible, respected performers people can relate to, encouraging them to take part", "How accessible, available and well-maintained a sport''s venues and equipment are", "The UK''s weather and terrain, which allow some activities easily but limit others needing snow, ice or warmth", "The chance to watch a sport in person, which can turn spectators into new fans and participants"]}'::jsonb, '{"answer": 0, "explain": "“Positive role models” means: Visible, respected performers people can relate to, encouraging them to take part"}'::jsonb),
('sport-studies:1-4-popularity-of-sport-in-the-uk:match:3b345356', 'sport-studies', 'sport-studies:1-4-popularity-of-sport-in-the-uk', '1.4 Popularity of Sport in the UK', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Social acceptability”?", "options": ["Whether wider society sees a sport as safe, fair and appropriate to take part in or watch", "How many people actually take part; a rise tends to raise a sport''s overall popularity", "The chance to watch a sport in person, which can turn spectators into new fans and participants", "Wins by individuals or teams at the highest level, which can cause a short-term surge in interest"]}'::jsonb, '{"answer": 0, "explain": "“Social acceptability” means: Whether wider society sees a sport as safe, fair and appropriate to take part in or watch"}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:exam:88285ce9', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'exam', 'mcq', 1, '{"num": "2", "question": "Which factor is most likely to help an emerging sport attract first-time participants?", "options": ["Removing every beginner session from the sport''s yearly calendar", "Short clips of the sport being shared widely on social media", "Permanently closing all local facilities that offer the sport", "Doubling the price of every entry-level session available"], "hint": "Think about what actually introduces new people to a sport they''ve never seen before.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Short clips of the sport being shared widely on social media.</strong></p>\n<ul>\n<li>Wide social media exposure introduces the sport to people who would never otherwise see it played.</li>\n<li>Removing sessions, closing facilities or raising prices would each make it harder, not easier, to attract first-timers.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:mcq:210f6324', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'mcq', 'mcq', 1, '{"question": "What best defines an emerging or new sport?", "options": ["A sport that is newly growing in popularity, provision and participation in the UK", "A sport that has kept exactly the same number of players and clubs for decades without any change", "A sport that can only ever be played by full-time professional athletes", "A sport that has been removed from a major international competition programme"]}'::jsonb, '{"answer": 0, "explain": "An emerging sport is one newly growing in popularity, provision and participation. Staying unchanged for decades, being elite-only, or being dropped from competition are the opposite of ''emerging''."}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:mcq:ee6e5c29', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'mcq', 'mcq', 1, '{"question": "Which of these is a genuine example of a sport that has recently been growing in the UK?", "options": ["A sport that has stayed at exactly the same participation level in the UK for over half a century", "Padel — a racket sport played in a small, walled court, usually in doubles", "A sport that no UK leisure centre or club currently offers to anyone", "A sport played only by full-time Olympic gold medallists at elite level"]}'::jsonb, '{"answer": 1, "explain": "Padel is a real example of a sport with newly opened courts and clubs across the UK. A stagnant, unavailable, or elite-only activity is not ''emerging''."}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:mcq:8627946f', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'mcq', 'mcq', 1, '{"question": "Which change is most likely to help an emerging sport grow by making it easier to actually try?", "options": ["A national governing body removes every beginner session from its yearly calendar", "The sport''s only professional league doubles its ticket prices for spectators", "A local leisure centre opens a new facility so people have somewhere nearby to try the sport", "All existing facilities and every beginner session for the sport are permanently closed without warning"]}'::jsonb, '{"answer": 2, "explain": "New, nearby provision is what lets first-timers actually try a sport. Removing sessions, raising prices, or closing facilities would all make it harder, not easier."}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:mcq:3f625c0c', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'mcq', 'mcq', 1, '{"question": "How can social media help an emerging sport attract new participants?", "options": ["It guarantees that every single viewer will immediately join a local sports club on that very same day without exception", "It only reaches people who already compete in the sport at an elite, professional level", "It replaces the need for any coaches, clubs or facilities to ever exist at all", "Short clips of matches and taster sessions can reach people who would never otherwise see the sport"]}'::jsonb, '{"answer": 3, "explain": "Social media widens exposure to people who wouldn''t otherwise see the sport. It doesn''t guarantee instant sign-ups, doesn''t only reach elite players, and doesn''t remove the need for real facilities."}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:mcq:f61da31d', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'mcq', 'mcq', 1, '{"question": "Why can a well-known role model help an emerging sport grow?", "options": ["Role models are legally required by law to try out every single emerging sport once a year without any exception whatsoever", "A respected player or coach can persuade people who would not otherwise try the sport to give it a go", "A role model automatically funds every new facility that the sport will ever need to succeed", "Role models only ever affect sports that are already extremely well established and popular"]}'::jsonb, '{"answer": 1, "explain": "A role model''s example builds trust and interest, encouraging new people to try the sport. There''s no legal requirement, no automatic funding, and role models can help sports at any stage, not only established ones."}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:mcq:f40ff547', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'mcq', 'mcq', 1, '{"question": "A student explains padel''s growth by writing only ''padel is popular now''. What is missing from this answer?", "options": ["Nothing at all — naming the sport is already enough to gain full marks here", "A complete, highly technical list of every single rule used in an official padel match, printed out in full", "A specific factor driving the growth (e.g. new facilities or media coverage) and a reason why it matters", "The exact date and country in which padel was first ever invented anywhere"]}'::jsonb, '{"answer": 2, "explain": "The marks come from a named factor plus a reason it drives growth — not from the sport''s name alone, its rulebook, or its invention date."}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:tf:e266ca21', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'tf', 'tf', 1, '{"question": "An emerging sport must be a completely new invention that has never existed anywhere in the world."}'::jsonb, '{"answer": false, "explain": "Many emerging sports already existed elsewhere, or on a small scale, for years. ''Emerging'' means newly growing in UK popularity, provision and participation, not necessarily brand new."}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:tf:c511609a', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'tf', 'tf', 1, '{"question": "Padel is an example of a racket sport that has recently been growing in the UK."}'::jsonb, '{"answer": true, "explain": "New padel courts and clubs have opened at leisure centres and tennis clubs across the UK in recent years, making it a genuine emerging-sport example."}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:tf:2d700150', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'tf', 'tf', 1, '{"question": "Media coverage and social media can help introduce an emerging sport to people who would not otherwise see it."}'::jsonb, '{"answer": true, "explain": "Wider exposure through TV, news or online clips is one of the main ways an emerging sport reaches people who had never come across it before."}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:tf:f49a717c', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'tf', 'tf', 1, '{"question": "Naming an emerging sport is enough on its own to earn full marks in an ''explain'' question."}'::jsonb, '{"answer": false, "explain": "Explain questions need a factor driving the growth plus a reason it matters — naming the sport alone earns very little."}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:tf:dfd06507', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'tf', 'tf', 1, '{"question": "Walking football is designed to be a slower, lower-impact version of football."}'::jsonb, '{"answer": true, "explain": "It removes running and reduces impact, which is exactly why it can attract people who want to play without the demands of the full-speed game."}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:tf:dfd5c5ce', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'tf', 'tf', 1, '{"question": "New facilities and low-cost taster sessions have no real effect on whether people try an emerging sport."}'::jsonb, '{"answer": false, "explain": "New, nearby facilities and free or low-cost sessions remove distance, cost and confidence as barriers, which can have a big effect on whether people take part."}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:learn:45d8a383', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'learn', 'mcq', 1, '{"readingTitle": "What is an ''emerging'' or ''new'' sport? — examples in the UK today", "reading": "<h4>The idea</h4>\n<ul>\n<li>An <strong>emerging (or new) sport</strong> is a sport that is <strong>newly growing</strong> in popularity, provision and participation in the UK — more people are starting to play it, and more places are starting to offer it.</li>\n<li>It does not have to be a brand-new invention. Many emerging sports already existed elsewhere, or on a small scale, and are only now becoming widely available in the UK.</li>\n</ul>\n<h4>Examples you can use in the exam</h4>\n<ul>\n<li><strong>Padel</strong> — a racket sport played in a small, walled court, usually in doubles. New courts have appeared at leisure centres and tennis clubs across the UK over recent years.</li>\n<li><strong>Walking football</strong> — a slower, no-running version of football, originally aimed at people who want to keep playing without the impact of the full-speed game.</li>\n<li><strong>Ultimate frisbee</strong> — a non-contact team sport where players score by catching a flying disc in an end zone; growing at universities and club level.</li>\n<li><strong>Competitive gaming (esports)</strong> — organised, competitive video-game play, watched live and via streaming, now run through organised leagues and school/college clubs.</li>\n<li>You can use any genuine example you know, as long as you can explain <em>why</em> it counts as newly growing.</li>\n</ul>", "question": "Which of these best describes an ''emerging'' or ''new'' sport?", "options": ["A sport that is newly growing in popularity, provision and participation in the UK", "A sport that has stayed exactly the same size and popularity in the UK for over half a century", "A sport that only exists at full-time, professional, elite level", "A sport that has been removed from a major international competition"]}'::jsonb, '{"answer": 0, "explain": "An emerging sport is newly growing — in players, provision and participation. A sport that never changes, or has been removed from competition, is the opposite of that."}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:learn:a464059d', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'learn', 'mcq', 1, '{"readingTitle": "How emerging sports develop — and the opportunities to take part", "reading": "<h4>Where the growth comes from</h4>\n<ul>\n<li><strong>New clubs and facilities</strong> — as a sport grows, leisure centres, schools and private operators start to offer it, so there are simply more places to try it.</li>\n<li><strong>Media exposure</strong> — TV highlights, online clips and news coverage introduce people to a sport they might never otherwise see.</li>\n<li><strong>Social media</strong> — short clips and online content can make a sport look exciting almost overnight, reaching audiences that traditional TV coverage misses.</li>\n<li><strong>Accessible, low-cost formats</strong> — many emerging sports are deliberately kept cheap and simple to start (free taster sessions, adapted rules, borrowed equipment), which removes cost and confidence as barriers.</li>\n<li><strong>Role models</strong> — a well-known player, or even a respected local coach, can persuade people who would not otherwise try the sport to give it a go.</li>\n</ul>\n<h4>The opportunities this creates</h4>\n<ul>\n<li>Beginners can join at a genuinely beginner level, because the whole sport is still new — there is less pressure to already be skilled.</li>\n<li>New clubs often need people to help shape the sport locally, as coaches, organisers or committee members — a different kind of opportunity to joining an already-established sport.</li>\n</ul>", "question": "Which factor most directly explains why a brand-new club can suddenly attract first-time participants?", "options": ["Short clips of the sport are shared widely and reach people who had never seen it before", "The sport has existed completely unchanged in the UK for over a century without any promotion", "The national governing body has decided to increase membership fees for every beginner", "Local facilities offering the sport have permanently stopped running any sessions at all"]}'::jsonb, '{"answer": 0, "explain": "Wide exposure (media/social media) is what introduces a growing sport to new people. An unchanged, unpromoted sport, higher fees, or closed facilities would not attract first-timers."}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:learn:e0376d2f', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'learn', 'mcq', 1, '{"readingTitle": "The exam skill: link the sport''s growth to the FACTOR driving it", "reading": "<h4>Don''t just describe the sport — explain WHY it''s growing</h4>\n<ul>\n<li>Weak answer: <em>\"Padel is becoming popular.\"</em> That''s a statement with no explanation.</li>\n<li>Strong answer: <em>\"Padel is becoming popular because new courts have opened at local leisure centres, and short clips of matches are shared widely on social media, which introduces the sport to people who had never seen it played before.\"</em></li>\n</ul>\n<h4>This links straight back to 1.4 Popularity</h4>\n<ul>\n<li>The same factors that make ANY sport more or less popular — <strong>media coverage, role models, provision/facilities, accessibility (including cost) and social acceptability</strong> — also explain why an emerging sport grows.</li>\n<li>So when a question asks about an emerging sport, apply the popularity factors you already know to the NEW example, rather than learning a separate list.</li>\n</ul>\n<h4>Common trap</h4>\n<ul>\n<li>Simply naming an emerging sport (\"padel\", \"walking football\") earns very little on its own. The marks are for the FACTOR driving its growth and the REASON that factor matters.</li>\n</ul>", "question": "A question asks why an emerging sport is increasing its participation. Which answer is most likely to score well?", "options": ["Naming the factor behind the growth (e.g. media coverage) and explaining why it increases participation", "Writing only the name of the emerging sport, with nothing else added at all", "Describing the official rules of the sport in as much extensive technical detail as you possibly can manage", "Listing as many different emerging sports as you are able to remember from revision"]}'::jsonb, '{"answer": 0, "explain": "Explain questions reward a factor plus a reason. Naming the sport, describing its rules, or listing more sports does not show the understanding the mark scheme rewards."}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:misc:a6fc293b', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> An ''emerging sport'' just means a brand new sport that nobody has ever played before anywhere in the world.</p><p><strong>✅ The correct idea:</strong> ''Emerging'' means newly growing in UK popularity, provision and participation — not necessarily a brand-new invention. Many examples (like padel) already existed elsewhere, or on a small scale, and are only now becoming widely available here.</p>", "question": "Which is the most accurate description of an ''emerging sport''?", "options": ["A sport that has only just been invented and never existed anywhere before", "A sport that is newly growing in popularity, provision and participation, even if it already existed elsewhere", "A sport that has been played at fully professional level in the UK continuously for well over a hundred years without any change", "A sport that has recently been removed from a major international competition"]}'::jsonb, '{"answer": 1, "explain": "Emerging just means newly growing here — the sport does not have to be a brand-new invention, and being long-established or removed from competition is the opposite idea."}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:misc:aa4fdf33', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> If a sport just gets media coverage, that''s the only thing that helps it grow — local facilities don''t matter.</p><p><strong>✅ The correct idea:</strong> Growth usually needs more than one factor together. Media coverage builds awareness, but if there is nowhere nearby to actually try the sport, that interest cannot easily turn into participation. Provision and exposure work together.</p>", "question": "A sport gets a lot of media coverage but has no local clubs or facilities nearby. What is most likely?", "options": ["Interest will still convert fully into participation with absolutely no other changes needed", "People who become interested may struggle to actually take part without nearby provision", "Media coverage always guarantees that new facilities will appear immediately", "Facilities have no effect whatsoever on whether people can take part in a sport"]}'::jsonb, '{"answer": 1, "explain": "Awareness alone does not create participation — without nearby provision, interested people have nowhere to actually try the sport."}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:misc:372f3d99', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Naming an emerging sport like ''padel'' or ''walking football'' is enough to answer an explain question.</p><p><strong>✅ The correct idea:</strong> Naming the sport earns very little. The marks come from identifying the FACTOR driving its growth (media, provision, role models, accessible/low-cost formats) and explaining WHY that factor increases participation.</p>", "question": "An exam question asks you to explain why an emerging sport is growing. What earns the marks?", "options": ["Simply writing the name of the sport with nothing else added at all", "Naming the factor behind the growth and explaining why it increases participation", "Listing every emerging sport that you happen to know about", "Describing the exact, official rules of the sport in complete technical detail from memory"]}'::jsonb, '{"answer": 1, "explain": "The mark scheme rewards a named factor plus a reason it drives participation, not the sport''s name, a list of sports, or its rulebook."}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:misc:c18b9348', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Emerging sports only appeal to young, fit, sporty people.</p><p><strong>✅ The correct idea:</strong> Many emerging sports are deliberately designed to be accessible to a wide range of ages and abilities (walking football is a clear example), which is part of why they can grow quickly among people who felt excluded from the traditional version.</p>", "question": "Why might an emerging sport like walking football appeal to a wider range of people?", "options": ["It is deliberately designed as a slower, lower-impact format accessible to more people", "It is only ever played by elite, full-time professional athletes", "It requires exactly the same high level of competitive fitness as senior traditional football", "It has stricter age restrictions than the traditional version of the sport"]}'::jsonb, '{"answer": 0, "explain": "Its slower, lower-impact design is exactly what widens who can take part, compared with the traditional, more demanding version."}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:tips:096dc2c4', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for this topic — what each one wants", "reading": "<p>Emerging-sport questions range from short recall to longer applied or evaluative answers. Match your answer to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify one emerging sport\" = one name, 1 mark.</li>\n<li><strong>Describe</strong> — say what the sport or the change involves, without necessarily giving a reason.</li>\n<li><strong>Explain</strong> — give a reason, using \"because\". Link the sport''s growth to a FACTOR (media coverage, role models, provision, accessibility, cost).</li>\n<li><strong>Discuss / Evaluate</strong> — weigh up more than one factor, apply them to a scenario, and reach a judgement about which matters most.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [4] in Section B usually wants two factors applied to the scenario; [6]/[8] levelled answers want balance and a justified judgement.</p>", "question": "A question says: ''Identify one emerging sport currently growing in the UK [1]''. What is the safest answer?", "options": ["A one-line explanation of why the sport is popular right now", "The name of one emerging sport, nothing more", "A full paragraph describing the sport''s entire history", "A list of every emerging sport you can possibly think of"]}'::jsonb, '{"answer": 1, "explain": "''Identify'' + [1] = one name, one mark. Explaining, writing a history, or listing several sports wastes time and risks marks being capped at one anyway."}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:tips:2499579d', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'tips', 'mcq', 1, '{"readingTitle": "tip — The golden rule: name the FACTOR and explain WHY it drives growth", "reading": "<p>The most common way to lose marks here is naming the sport with no factor. Build every answer as <strong>factor → effect on participation</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"Padel is growing.\"</li>\n<li><strong>✅ full marks:</strong> \"Padel is growing because new courts have opened at local leisure centres, giving people somewhere nearby to try it for the first time.\"</li>\n</ul>\n<p>In <strong>Section B</strong> you are given a scenario. Use a detail <em>from that scenario</em> (a named club, a named change) rather than a general example.</p>", "question": "In a Section B scenario about a named club promoting an emerging sport, your explanation should be based on...", "options": ["any emerging sport that you personally happen to enjoy the most", "the details given in the scenario you are given", "a professional athlete not mentioned anywhere in the question", "your own school''s usual PE lesson only, regardless of the scenario"]}'::jsonb, '{"answer": 1, "explain": "Section B is applied — the marks are for using the scenario in front of you, not a general example that ignores it."}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:tips:ea18c56b', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where this appears + sentence starters", "reading": "<p><strong>Where it shows up:</strong> emerging sports appear as quick recall in <strong>Section A</strong> (name a sport/factor), as applied points in <strong>Section B</strong> scenarios about a club or provider promoting a new sport, and can feed a <strong>Section C</strong> Discuss/Evaluate answer about increasing participation.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Keep two or three real examples ready (e.g. padel, walking football, ultimate frisbee) so you always have something to apply.</li>\n<li>For every example, memorise ONE factor driving its growth — that factor is usually where the mark is.</li>\n<li>Link back to 1.4 Popularity: the same factors (media, role models, provision, accessibility, social acceptability) explain growth here too.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One way [sport] could increase its participation is… because…\"</li>\n<li>\"This matters because it removes the barrier of…\"</li>\n<li>\"However, this change might not help everyone, because…\"</li>\n</ul>", "question": "Why is it useful to link an emerging sport''s growth back to the popularity factors from 1.4?", "options": ["Because it lets you reuse understanding you already have, applied to a new example", "Because emerging sports use a completely different, unrelated set of factors", "Because the exam never asks about emerging sports in Section B or C", "Because popularity factors only ever apply to sports that are already well established"]}'::jsonb, '{"answer": 0, "explain": "The same factors (media, role models, provision, accessibility, social acceptability) explain growth for both established and emerging sports, so you can reuse what you already know."}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:fib:6e60b3a4', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'fib', 'fib', 1, '{"question": "An emerging sport is one that is newly _____ in popularity, provision and participation in the UK.", "blankOptions": {"B1": ["media", "court", "growing", "impact"]}}'::jsonb, '{"blanks": {"B1": "growing"}}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:fib:6957f6f8', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'fib', 'fib', 1, '{"question": "Padel is a racket sport played in a small, walled _____, usually in doubles.", "blankOptions": {"B1": ["impact", "media", "court", "nearby"]}}'::jsonb, '{"blanks": {"B1": "court"}}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:fib:e2834c32', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'fib', 'fib', 1, '{"question": "Walking football is a slower, no-running version of football aimed at players who want lower _____.", "blankOptions": {"B1": ["court", "media", "impact", "nearby"]}}'::jsonb, '{"blanks": {"B1": "impact"}}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:fib:422216d6', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'fib', 'fib', 1, '{"question": "New clubs and facilities give people somewhere _____ to try an emerging sport for the first time.", "blankOptions": {"B1": ["court", "media", "nearby", "impact"]}}'::jsonb, '{"blanks": {"B1": "nearby"}}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:fib:473d1335', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'fib', 'fib', 1, '{"question": "Short clips shared on social _____ can introduce a sport to people who would never otherwise see it.", "blankOptions": {"B1": ["growing", "impact", "court", "media"]}}'::jsonb, '{"blanks": {"B1": "media"}}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:match:0dbc3798', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Emerging sport”?", "options": ["New clubs, facilities or sessions that give people somewhere nearby to try a sport", "A racket sport played in a small, walled court, usually in doubles", "A sport that is newly growing in popularity, provision and participation in the UK", "A non-contact team sport where players score by catching a flying disc in an end zone"]}'::jsonb, '{"answer": 2, "explain": "“Emerging sport” means: A sport that is newly growing in popularity, provision and participation in the UK"}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:match:9b4cf3d4', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Padel”?", "options": ["New clubs, facilities or sessions that give people somewhere nearby to try a sport", "A slower, no-running version of football aimed at lower-impact participation", "A racket sport played in a small, walled court, usually in doubles", "A well-known player or coach whose example persuades new people to try a sport"]}'::jsonb, '{"answer": 2, "explain": "“Padel” means: A racket sport played in a small, walled court, usually in doubles"}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:match:7ff3fbbb', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Walking football”?", "options": ["A slower, no-running version of football aimed at lower-impact participation", "New clubs, facilities or sessions that give people somewhere nearby to try a sport", "A racket sport played in a small, walled court, usually in doubles", "A non-contact team sport where players score by catching a flying disc in an end zone"]}'::jsonb, '{"answer": 0, "explain": "“Walking football” means: A slower, no-running version of football aimed at lower-impact participation"}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:match:e0728abb', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Ultimate frisbee”?", "options": ["A slower, no-running version of football aimed at lower-impact participation", "A sport that is newly growing in popularity, provision and participation in the UK", "New clubs, facilities or sessions that give people somewhere nearby to try a sport", "A non-contact team sport where players score by catching a flying disc in an end zone"]}'::jsonb, '{"answer": 3, "explain": "“Ultimate frisbee” means: A non-contact team sport where players score by catching a flying disc in an end zone"}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:match:4625e47d', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Provision (growth factor)”?", "options": ["A sport that is newly growing in popularity, provision and participation in the UK", "New clubs, facilities or sessions that give people somewhere nearby to try a sport", "A racket sport played in a small, walled court, usually in doubles", "A non-contact team sport where players score by catching a flying disc in an end zone"]}'::jsonb, '{"answer": 1, "explain": "“Provision (growth factor)” means: New clubs, facilities or sessions that give people somewhere nearby to try a sport"}'::jsonb),
('sport-studies:1-5-emerging-and-new-sports:match:cfdd54ca', 'sport-studies', 'sport-studies:1-5-emerging-and-new-sports', '1.5 Emerging and New Sports', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Role model (growth factor)”?", "options": ["A sport that is newly growing in popularity, provision and participation in the UK", "New clubs, facilities or sessions that give people somewhere nearby to try a sport", "A non-contact team sport where players score by catching a flying disc in an end zone", "A well-known player or coach whose example persuades new people to try a sport"]}'::jsonb, '{"answer": 3, "explain": "“Role model (growth factor)” means: A well-known player or coach whose example persuades new people to try a sport"}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:exam:2865d744', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'exam', 'mcq', 1, '{"num": "2", "question": "Two opponents from different countries swap shirts after a match, showing an appreciation of each other''s culture. Which value does this show?", "options": ["National pride — a shared sense of identity created by supporting the same national team", "Tolerance and respect — a greater understanding and appreciation of another culture", "Excellence — striving to be your best and always giving maximum effort", "Team spirit — supporting teammates as they work toward a shared goal"], "hint": "Think about which value is specifically about understanding people from other cultures.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Tolerance and respect.</strong></p>\n<ul>\n<li>Appreciating an opponent''s culture after a hard-fought game is the definition of tolerance and respect.</li>\n<li>The other options describe national pride, excellence and team spirit instead, none of which is about understanding another culture.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:mcq:078e4816', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'mcq', 'mcq', 1, '{"question": "Which two ideas does the specification treat as ONE single combined value, not two separate values?", "options": ["Team spirit and fair play, because supporting teammates and following the rules are always the same thing", "Tolerance and respect, which together mean gaining a greater understanding of other cultures and backgrounds", "Inclusion and national pride, since giving everyone a fair chance to play is identical to supporting a country", "Citizenship and excellence, because building local community links is the same as striving to be your best"]}'::jsonb, '{"answer": 1, "explain": "Tolerance and respect are always marked as a single combined value. The other three pairs (team spirit/fair play, inclusion/national pride, citizenship/excellence) are all separate values."}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:mcq:fa1c16e8', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'mcq', 'mcq', 1, '{"question": "A substitute who has not been picked to play still shouts encouragement to teammates chasing a shared goal. Which value is this?", "options": ["Team spirit — supporting and encouraging teammates while everyone works toward the same shared goal", "Fair play — following the written rules of the game and never attempting to cheat an opponent", "National pride — supporting a national team so that lots of very different people feel one shared sense of identity", "Excellence — pushing yourself with maximum effort so that your own performance keeps improving"]}'::jsonb, '{"answer": 0, "explain": "Encouraging teammates toward a shared goal, even without playing, is team spirit — the other options describe fair play, national pride and excellence instead."}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:mcq:9c721eb8', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'mcq', 'mcq', 1, '{"question": "A local sports club runs free junior coaching sessions and builds stronger links across its neighbourhood. Which value does this best show?", "options": ["Inclusion — making sure people from every social group get an equal opportunity to take part", "Citizenship — using sport to build positive links and connections within the local community", "National pride — creating a shared sense of identity by supporting the same national team", "Fair play — competing honestly, following the rules and accepting decisions made by officials"]}'::jsonb, '{"answer": 1, "explain": "Building links within the local community through a club''s coaching sessions is citizenship — not inclusion, national pride or fair play."}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:mcq:68d45ab3', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'mcq', 'mcq', 1, '{"question": "After the final whistle, two opponents from different countries swap shirts and thank each other for a hard-fought game. Which value does this best show?", "options": ["National pride — a shared sense of identity created by supporting the same national team", "Excellence — striving to be your best and always giving maximum effort in competition", "Tolerance and respect — a greater understanding and appreciation of another culture", "Team spirit — supporting teammates as they work together toward one shared goal"]}'::jsonb, '{"answer": 2, "explain": "Appreciating an opponent from a different culture after the game shows tolerance and respect, not national pride, excellence or team spirit."}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:mcq:a8f8407b', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'mcq', 'mcq', 1, '{"question": "A walking-football session is deliberately opened up to players of any age, gender or fitness level. Which value does this best show?", "options": ["Fair play — following the agreed rules of the game and accepting the referee''s decisions", "Excellence — trying your hardest to keep improving your own personal performance", "Inclusion — giving people from every social group an equal opportunity to take part", "Citizenship — building positive links and connections within the local community"]}'::jsonb, '{"answer": 2, "explain": "Welcoming every age, gender and fitness level is inclusion — not fair play, excellence or citizenship."}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:mcq:d995c734', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'mcq', 'mcq', 1, '{"question": "Thousands of fans from many different backgrounds come together to cheer for the same national team at a major tournament. Which value does this best show?", "options": ["Citizenship — using sport to build stronger links and connections within a local community", "Fair play — competing honestly, following the rules, and accepting the officials'' decisions", "Inclusion — giving people from every social group an equal chance to take part in sport", "National pride — supporting a national team creates a shared sense of identity and unity"]}'::jsonb, '{"answer": 3, "explain": "Fans of different backgrounds uniting behind one national team is national pride — not citizenship, fair play or inclusion."}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:tf:e07b1803', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'tf', 'tf', 1, '{"question": "Tolerance and respect are treated as one combined value in the specification, not two separate values."}'::jsonb, '{"answer": true, "explain": "Writing them as two separate values does not earn extra marks — the mark scheme only credits this once, as a single combined value."}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:tf:e3da1f94', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'tf', 'tf', 1, '{"question": "Team spirit only applies to players who are actually selected to play in a match."}'::jsonb, '{"answer": false, "explain": "A substitute or non-playing squad member can still show team spirit by encouraging and supporting the team from the sidelines."}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:tf:2e42c442', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'tf', 'tf', 1, '{"question": "Citizenship in this context means the same thing as legally holding a passport for a country."}'::jsonb, '{"answer": false, "explain": "Citizenship here means building positive links within the local community through sport — it has nothing to do with passports or nationality."}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:tf:1161f27a', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'tf', 'tf', 1, '{"question": "National pride can bring people from very different backgrounds together to support the same team."}'::jsonb, '{"answer": true, "explain": "Supporting a national team can create a shared sense of identity and unity across people who otherwise have little in common."}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:tf:a890f7aa', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'tf', 'tf', 1, '{"question": "Inclusion means that only people with a disability should be given the opportunity to take part."}'::jsonb, '{"answer": false, "explain": "Inclusion means giving people from every social group an equal opportunity — not restricting participation to just one group."}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:tf:3d7126a8', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'tf', 'tf', 1, '{"question": "Excellence simply means winning every competition you enter."}'::jsonb, '{"answer": false, "explain": "Excellence means striving to be your best and giving maximum effort to improve — it is not the same as always winning."}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:learn:7a970c0f', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'learn', 'mcq', 1, '{"readingTitle": "What ''values promoted through sport'' means", "reading": "<h4>The idea</h4>\n<ul>\n<li>Taking part in sport is not only about physical activity — it can also build <strong>positive attitudes and behaviours</strong> that matter in everyday life, both on the pitch and off it.</li>\n<li>The specification names seven values that sport can promote: <strong>team spirit, fair play, citizenship, tolerance and respect, inclusion, national pride</strong> and <strong>excellence</strong>.</li>\n</ul>\n<h4>The trap the exam is designed to catch</h4>\n<ul>\n<li><strong>\"Tolerance and respect\" is ONE combined value, not two.</strong> Students often write them as two separate values to try to pick up two marks — that loses marks rather than gaining them, because the mark scheme only credits it once.</li>\n<li>Together they mean gaining a <strong>greater understanding of other cultures</strong> and ways of doing things through contact with people in sport.</li>\n</ul>\n<h4>How to answer well</h4>\n<ul>\n<li>Every mark on this topic rewards <strong>naming the value AND giving a sporting example</strong> that actually shows it happening — never the name on its own.</li>\n</ul>", "question": "How many separate values does the specification treat ''tolerance'' and ''respect'' as?", "options": ["One — tolerance and respect are treated as a single combined value in the specification", "Two — tolerance and respect are two entirely separate values in the specification", "Three — tolerance, respect and understanding are three separate values in the specification", "Zero — neither tolerance nor respect appears anywhere in the specification"]}'::jsonb, '{"answer": 0, "explain": "Tolerance and respect are always marked as ONE combined value — writing them as two separate values does not earn two marks."}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:learn:bc830ac2', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'learn', 'mcq', 1, '{"readingTitle": "Team spirit, fair play and citizenship", "reading": "<h4>Team spirit</h4>\n<ul>\n<li><strong>Team spirit</strong> — supporting and encouraging your teammates as everyone works together toward a shared goal.</li>\n<li>Sporting example: a substitute who has not been picked to play still shouts encouragement from the bench, and players cover for a tired teammate rather than criticising them.</li>\n</ul>\n<h4>Fair play</h4>\n<ul>\n<li><strong>Fair play</strong> — following the rules honestly, never trying to cheat, and accepting decisions made by officials even when you disagree.</li>\n<li>Sporting example: a footballer tells the referee that the ball crossed the line for a throw-in even though the referee missed it and had given the decision the player''s way.</li>\n</ul>\n<h4>Citizenship</h4>\n<ul>\n<li><strong>Citizenship</strong> — using sport to build positive links and connections within the local community.</li>\n<li>Sporting example: players from a local club volunteer as coaches for a youth team, building stronger relationships across the neighbourhood.</li>\n</ul>", "question": "A substitute who is not selected to play still calls out encouragement to teammates working toward the same shared goal. Which value is this showing?", "options": ["Team spirit — supporting and encouraging teammates as everyone works toward a shared goal", "Fair play — following the written rules honestly and accepting every decision officials make", "Citizenship — using sport to build positive links within the local community", "Excellence — striving to be your best by giving maximum effort in competition"]}'::jsonb, '{"answer": 0, "explain": "Encouraging teammates toward a shared goal, even from the bench, is team spirit — not fair play, citizenship or excellence."}'::jsonb),
('sport-studies:2-1-values-promoted-through-sport:learn:66d14342', 'sport-studies', 'sport-studies:2-1-values-promoted-through-sport', '2.1 Values Promoted Through Sport', 'learn', 'mcq', 1, '{"readingTitle": "Tolerance and respect, inclusion, national pride and excellence", "reading": "<h4>Tolerance and respect (ONE value)</h4>\n<ul>\n<li>A greater understanding and appreciation of people from <strong>other cultures</strong> and backgrounds, gained through contact in sport.</li>\n<li>Sporting example: after the final whistle, two opponents from different countries swap shirts and thank each other for a hard-fought game.</li>\n</ul>\n<h4>Inclusion</h4>\n<ul>\n<li>Giving people from <strong>every social group</strong> an equal opportunity to take part, whatever their background, ability or gender.</li>\n<li>Sporting example: a walking-football session is deliberately opened up to players of any age, gender or fitness level.</li>\n</ul>\n<h4>National pride</h4>\n<ul>\n<li>Supporting a national team in a way that creates a <strong>shared sense of identity and unity</strong> among very different people.</li>\n<li>Sporting example: thousands of fans from many different backgrounds come together to cheer for the same national team at a major tournament.</li>\n</ul>\n<h4>Excellence</h4>\n<ul>\n<li>Striving to be your best by giving <strong>maximum effort</strong> and always trying to improve.</li>\n<li>Sporting example: an athlete pushes through a demanding training block purely to improve their own personal best time.</li>\n</ul>", "question": "A council builds stronger links across its town by running free sessions through local sports clubs. Which value does this best describe?", "options": ["National pride — supporting a national team creates one shared sense of identity and unity for everyone", "Citizenship — using sport to build positive links and connections within the local community", "Inclusion — giving people from every social group an equal opportunity to take part", "Tolerance and respect — a greater understanding and appreciation of another culture"]}'::jsonb, '{"answer": 1, "explain": "Building links within the local community through sport is citizenship, not national pride, inclusion or tolerance and respect."}'::jsonb)
